<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Factories\HasFactory;
class Product extends Model{use HasFactory;protected $fillable=['category_id','brand_id','name','slug','short_description','description','specifications','pros','cons','thumbnail','worth_it_score','lowest_price','status','is_featured','is_trending','admin_score_adjustment'];protected $casts=['specifications'=>'array','pros'=>'array','cons'=>'array','is_featured'=>'boolean','is_trending'=>'boolean'];public function scopePublished($q){return $q->where('status','published');}public function category(){return $this->belongsTo(Category::class);}public function brand(){return $this->belongsTo(Brand::class);}public function images(){return $this->hasMany(ProductImage::class);}public function prices(){return $this->hasMany(ProductPrice::class);}public function affiliateLinks(){return $this->hasMany(AffiliateLink::class);}public function articles(){return $this->belongsToMany(Article::class,'article_product');}public function bestPrice(){return $this->prices->sortBy('price')->first();}}
